import React, { useState } from 'react';
import { useData } from '../../context/DataContext';
import { useAuth } from '../../context/AuthContext';

const Reports = () => {
  const { user } = useAuth();
  const { tasks, staffList, facilityLogs } = useData();
  const isChief = user?.role === 'chief';

  const [filterStaff, setFilterStaff] = useState('');
  const [filterMonth, setFilterMonth] = useState('');

  // Helper tính thu nhập
  const calculateIncome = (staff) => {
      const ubi1 = (staff.ubi1Base || 0) * (staff.ubi1Percent || 0) / 100;
      const ubi2 = (staff.ubi2Base || 0) * (staff.ubi2Percent || 0) / 100;
      return ubi1 + ubi2 + (staff.remuneration || 0);
  };
  const totalCompanyIncome = staffList.reduce((acc, s) => acc + calculateIncome(s), 0);

  // Logic lọc tasks
  const filteredTasks = tasks.filter(t => {
    let matchStaff = filterStaff ? (t.assigneeId === filterStaff) : true;
    let matchTime = filterMonth ? t.endTime.startsWith(filterMonth) : true;
    return matchStaff && matchTime;
  });

  return (
    <div style={{ padding: '20px' }}>
      <div className="no-print" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
        <h2>Báo cáo Tổng hợp</h2>
        <button onClick={() => window.print()} style={{ padding: '10px 20px', background: '#003366', color: 'white', border: 'none', cursor: 'pointer' }}>In Báo Cáo</button>
      </div>

      {/* 1. TỔNG THU NHẬP (CHIEF ONLY) */}
      {isChief && (
          <div style={{ marginBottom: '30px', background: '#f0fdf4', padding: '20px', borderRadius: '8px', border: '1px solid #bbf7d0' }}>
              <h3 style={{ color: '#166534', marginTop: 0 }}>📊 Tài chính & Thu nhập (Chief Admin)</h3>
              <h1 style={{ margin: '10px 0', color: '#14532d' }}>Tổng quỹ lương: {totalCompanyIncome.toLocaleString()} VNĐ</h1>
              
              <details>
                  <summary style={{cursor:'pointer', fontWeight:'bold', color: '#166534'}}>Xem chi tiết từng nhân sự ▼</summary>
                  <table style={{width:'100%', marginTop:'10px', background:'white', borderCollapse:'collapse'}}>
                      <thead>
                          <tr style={{textAlign:'left', background:'#dcfce7'}}><th style={{padding:'8px'}}>Nhân sự</th><th>UBI 1</th><th>UBI 2</th><th>Thù lao</th><th>Tổng</th></tr>
                      </thead>
                      <tbody>
                          {staffList.map(s => {
                              const ubi1 = (s.ubi1Base||0)*(s.ubi1Percent||0)/100;
                              const ubi2 = (s.ubi2Base||0)*(s.ubi2Percent||0)/100;
                              return (
                                  <tr key={s.id} style={{borderBottom:'1px solid #eee'}}>
                                      <td style={{padding:'8px'}}>{s.name}</td>
                                      <td>{ubi1.toLocaleString()}</td>
                                      <td>{ubi2.toLocaleString()}</td>
                                      <td>{(s.remuneration||0).toLocaleString()}</td>
                                      <td style={{fontWeight:'bold'}}>{calculateIncome(s).toLocaleString()}</td>
                                  </tr>
                              );
                          })}
                      </tbody>
                  </table>
              </details>
          </div>
      )}

      {/* 2. BÁO CÁO CSVC */}
      <div style={{ marginBottom: '30px', background: 'white', padding: '20px', borderRadius: '8px', boxShadow: '0 2px 5px rgba(0,0,0,0.1)' }}>
          <h3 style={{ color: '#003366', marginTop: 0 }}>🛠️ Tình trạng Cơ sở vật chất</h3>
          <div style={{maxHeight:'300px', overflowY:'auto'}}>
            <table border="1" style={{ width: '100%', borderCollapse: 'collapse', fontSize: '0.9rem' }}>
                <thead><tr style={{background:'#eee'}}><th style={{padding:'8px'}}>Thời gian</th><th>Khu vực</th><th>Người check</th><th>Hạng mục</th><th>Trạng thái</th></tr></thead>
                <tbody>
                    {facilityLogs.length === 0 ? <tr><td colSpan="5" style={{padding:'10px', textAlign:'center'}}>Chưa có dữ liệu</td></tr> : 
                    facilityLogs.sort((a,b) => new Date(b.timestamp) - new Date(a.timestamp)).map(log => (
                        <tr key={log.id}>
                            <td style={{padding:'6px'}}>{new Date(log.timestamp).toLocaleString()}</td>
                            <td>{log.area} ({log.type})</td>
                            <td>{log.staffName}</td>
                            <td>{log.item}</td>
                            <td style={{color: (log.status.includes('Tốt') || log.status.includes('Mát') || log.status.includes('Ổn định') || log.status.includes('Xanh')) ? 'green' : 'red', fontWeight:'bold'}}>{log.status}</td>
                        </tr>
                    ))}
                </tbody>
            </table>
          </div>
      </div>

      {/* 3. BÁO CÁO TIẾN ĐỘ */}
      <div style={{ background: 'white', padding: '20px', borderRadius: '8px', boxShadow: '0 2px 5px rgba(0,0,0,0.1)' }}>
        <h3 style={{ color: '#003366', marginTop: 0 }}>📋 Tiến độ công việc</h3>
        
        <div className="no-print" style={{ marginBottom: '15px' }}>
            Lọc theo nhân sự: 
            <select onChange={e => setFilterStaff(e.target.value)} style={{marginLeft:'5px', padding:'5px'}}>
                <option value="">Tất cả</option>
                {staffList.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
            </select>
        </div>

        <table border="1" style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead>
            <tr style={{ background: '#eee' }}>
              <th style={{padding:'8px'}}>Nhân sự</th><th>Công việc</th><th>Hạn chót</th><th>Tiến độ</th><th>Ghi chú</th>
            </tr>
          </thead>
          <tbody>
            {filteredTasks.length === 0 ? <tr><td colSpan="5" style={{textAlign:'center', padding:'10px'}}>Không có nhiệm vụ</td></tr> :
            filteredTasks.map(task => {
              const staff = staffList.find(s => s.id === task.assigneeId);
              return (
                <tr key={task.id}>
                  <td style={{ padding: '8px' }}>{staff?.name}</td>
                  <td style={{ padding: '8px' }}>{task.title}</td>
                  <td style={{ padding: '8px' }}>{new Date(task.endTime).toLocaleString()}</td>
                  <td style={{ padding: '8px', textAlign: 'center' }}>{task.progress}%</td>
                  <td style={{ padding: '8px' }}>{task.progress < 100 ? (task.reason || 'Đang thực hiện') : 'Hoàn thành'}</td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default Reports;
